#include <bits/stdc++.h>
using namespace std;
const int N=85;
__int128 n,m,dp[N][N],a[N],num[85],ans;
__int128 read(){
	__int128 k=0,f=1;
    char c=getchar();
    while(!isdigit(c)){
        if(c=='-')f=-1;
        c=getchar();
    }
    while(isdigit(c)){
    	k=(k<<3)+(k<<1)+(c^48);
		c=getchar();
	}
    return k*f;
}
void print(__int128 x){
	if(x<0)putchar('-'),x=-x;
    if(x<10)putchar(x^48);
    else print(x/10),putchar(x%10^48);
}
void prepare()
{
    num[0]=1;
    for(int i=1;i<=80;i++)
    {
        num[i]=num[i-1]*2;
        // cout<<num[i]<<" ";
    }
}
int main()
{
    n=read();m=read();
    prepare();
    for(__int128 num1=1;num1<=n;num1++)
    {
        for(__int128 i=1;i<=m;i++)
        {
            a[i]=read();
        }
        for(__int128 len=m;len>0;len--)
        {
            for(__int128 l=1,r=len;r<=m;l++,r++)
            {
                dp[l][r]=max(dp[l-1][r]+num[m-r+l-1]*a[l-1],dp[l][r+1]+num[m-r+l-1]*a[r+1]);
                // cout<<dp[l][r]<<"\n";
            }
        }
        __int128 mx=-1;
        for(__int128 i=1;i<=m;i++)
        {
            mx=max(mx,dp[i][i]+num[m]*a[i]);
        }
        ans+=mx;
    }
    print(ans);
    return 0;
}
